qss:
QWidget { background: #07101c; color: #ecf7ff; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #07101c; }
QGroupBox { background: #0d1728; border: 1px solid #3a7a8c; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #75ffcc; }
QTabWidget::pane { border: 1px solid #3a7a8c; background: #0d1728; }
QTabBar::tab { background: #100d24; color: #ecf7ff; padding: 8px 14px; border: 1px solid #3a7a8c; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #2652a3; color: #f5ffff; font-weight: bold; }
QTabBar::tab:hover { background: #1b3b70; color: #f5ffff; }
QPushButton { background: #16345f; color: #f5ffff; border: 1px solid #75ffcc; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #22a98f; color: #061016; }
QPushButton:disabled { background: #39475c; color: #8492a8; border-color: #455873; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #080a18; color: #ecf7ff; border: 1px solid #3a7a8c; border-radius: 5px; padding: 5px; selection-background-color: #7c4dff; selection-color: #ffffff; }
QComboBox QAbstractItemView { background: #080a18; color: #ecf7ff; selection-background-color: #7c4dff; selection-color: #ffffff; border: 1px solid #3a7a8c; }
QTableWidget { background: #080a18; alternate-background-color: #0f1f32; color: #ecf7ff; gridline-color: #2a5d75; selection-background-color: #2652a3; selection-color: #ffffff; }
QHeaderView::section { background: #15355f; color: #ecf7ff; padding: 6px; border: 1px solid #3a7a8c; font-weight: bold; }
QScrollBar:vertical { background: #0d1728; width: 14px; }
QScrollBar::handle:vertical { background: #75ffcc; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #0d1728; height: 14px; }
QScrollBar::handle:horizontal { background: #75ffcc; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #ecf7ff; }
